INSERT INTO seed_payloads (table_name, payload_json) VALUES ('translations', N'[{"id":"trans-c267c49e","entityType":"place","entityId":"place-bbq-night","languageCode":"zh-CN","title":"Quảng Trường Ẩm thực BBQ Night","shortText":"","fullText":"烧烤之夜是永庆美食街的一大亮点，游客可以在这里通过烤海鲜的香气和热闹的当地氛围，体验西贡充满活力的街头生活。","seoTitle":"","seoDescription":"","isPremium":true,"updatedBy":"Nguyễn Thanh Hà","updatedAt":"2026-03-21T03:10:22.6481221+00:00"},{"id":"trans-1","entityType":"place","entityId":"place-bbq-night","languageCode":"vi","title":"Quảng trường Ẩm thực BBQ Night","shortText":"Điểm tụ họp sôi động với món nướng hải sản và không khí phố đêm náo nhiệt.","fullText":"BBQ Night là điểm dừng chân nổi bật của Phố Ẩm thực Vĩnh Khánh, nơi du khách có thể cảm nhận nhịp sống đường phố Sài Gòn qua hương thơm của hải sản nướng và không khí tụ họp đậm chất địa phương.","seoTitle":"BBQ Night - Phố Ẩm thực Vĩnh Khánh","seoDescription":"Điểm nướng hải sản nổi bật cho nhóm bạn và khách du lịch về đêm.","isPremium":false,"updatedBy":"Trần Minh Thu","updatedAt":"2026-03-21T02:26:09.7445012+00:00"},{"id":"trans-2","entityType":"place","entityId":"place-bbq-night","languageCode":"en","title":"BBQ Night Culinary Square","shortText":"A lively seafood grill stop with upbeat local night-street energy.","fullText":"BBQ Night is one of the key anchors of Vinh Khanh Food Street, bringing together fresh grilled seafood, bright urban lights, and an informal local social vibe.","seoTitle":"BBQ Night at Vinh Khanh Food Street","seoDescription":"Seafood grill spot for evening food tours in District 4.","isPremium":false,"updatedBy":"Trần Minh Thu","updatedAt":"2026-03-18T07:05:00+00:00"},{"id":"trans-3","entityType":"place","entityId":"place-snail-signature","languageCode":"vi","title":"Quán Ốc Vĩnh Khánh Signature","shortText":"Quán ốc đặc trưng với thực đơn đa dạng, phù hợp khách lần đầu đến khu phố.","fullText":"Nằm giữa tuyến phố nhộn nhịp, quán ốc này đại diện cho tinh thần ẩm thực đường phố Quận 4: giá hợp lý, chế biến nhanh, vị đậm và luôn đông khách địa phương lẫn khách quốc tế.","seoTitle":"Quán ốc nổi bật tại Vĩnh Khánh","seoDescription":"Thưởng thức ốc, sò, nghêu chế biến đậm vị tại Quận 4.","isPremium":false,"updatedBy":"Trần Minh Thu","updatedAt":"2026-03-19T09:25:00+00:00"},{"id":"trans-4","entityType":"place","entityId":"place-snail-signature","languageCode":"en","title":"Vinh Khanh Signature Snail House","shortText":"An iconic snail and shellfish stop for first-time visitors.","fullText":"This destination captures District 4 street dining at its most energetic, with a broad seafood menu and quick service.","seoTitle":"Signature Snail House in Vinh Khanh","seoDescription":"Iconic seafood and snail experience for tourists and locals.","isPremium":false,"updatedBy":"Trần Minh Thu","updatedAt":"2026-03-19T09:05:00+00:00"},{"id":"trans-5","entityType":"place","entityId":"place-sweet-lane","languageCode":"vi","title":"Hẻm Chè Vĩnh Khánh","shortText":"Điểm tráng miệng và món ngọt giúp cân bằng hành trình ăn uống.","fullText":"Không gian nhỏ nhưng thân thiện, phù hợp để kết thúc tuyến tham quan ẩm thực với các món chè, sữa chua và đồ ăn vặt mát lạnh.","seoTitle":"Hẻm chè Vĩnh Khánh","seoDescription":"Điểm dừng món ngọt phù hợp cho gia đình và khách trẻ.","isPremium":false,"updatedBy":"Phạm Mỹ Linh","updatedAt":"2026-03-16T07:10:00+00:00"}]');
